import React, { useState } from "react";
import { useAuth } from "../context/AuthContext";
import api from "../utils/api";
import toast from "react-hot-toast";

export default function Profile() {
  const { user, updateProfile } = useAuth();

  const [name, setName] = useState(user?.name || "");
  const [avatar, setAvatar] = useState(user?.avatar || "");
  const [avatarPreview, setAvatarPreview] = useState(user?.avatar || "");
  const [currentPassword, setCurrentPassword] = useState("");
  const [newPassword, setNewPassword] = useState("");
  const [loading, setLoading] = useState(false);

  // Handle avatar upload (image file → base64)
  const handleAvatarUpload = (e) => {
    const file = e.target.files[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = () => {
      setAvatar(reader.result);
      setAvatarPreview(reader.result);
    };
    reader.readAsDataURL(file);
  };

  const handleUpdateProfile = async () => {
    if (!name.trim()) {
      toast.error("Name is required");
      return;
    }

    try {
      setLoading(true);
      await updateProfile({ name, avatar });
      toast.success("Profile updated successfully");
    } catch {
      toast.error("Update failed");
    } finally {
      setLoading(false);
    }
  };

  const handleChangePassword = async () => {
    if (!currentPassword || !newPassword) {
      toast.error("Please fill both password fields");
      return;
    }

    try {
      setLoading(true);
      await api.put("/auth/password", {
        currentPassword,
        newPassword,
      });

      toast.success("Password changed successfully");
      setCurrentPassword("");
      setNewPassword("");
    } catch {
      toast.error("Current password is incorrect");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-2xl mx-auto p-6">
      <div className="bg-white dark:bg-gray-900 rounded-2xl shadow-lg p-8 space-y-8">
        {/* Header */}
        <div className="flex items-center gap-6">
          <div className="relative">
            <img
              src={avatarPreview || "https://ui-avatars.com/api/?name=" + name}
              alt="avatar"
              className="w-28 h-28 rounded-full object-cover border-4 border-primary-500 shadow-md"
            />

            <label className="absolute bottom-0 right-0 bg-primary-600 text-white p-2 rounded-full cursor-pointer hover:bg-primary-700 transition">
              ✏️
              <input
                type="file"
                accept="image/*"
                onChange={handleAvatarUpload}
                hidden
              />
            </label>
          </div>

          <div>
            <h2 className="text-2xl font-bold">👤 Profile</h2>
            <p className="text-gray-500 text-sm">
              Manage your personal information
            </p>
          </div>
        </div>

        {/* Name */}
        <div className="space-y-2">
          <label className="form-label font-semibold">Full Name</label>
          <input
            className="input w-full"
            value={name}
            onChange={(e) => setName(e.target.value)}
            placeholder="Enter your name"
          />
        </div>

        <button
          className="btn btn-primary w-full"
          onClick={handleUpdateProfile}
          disabled={loading}
        >
          {loading ? "Updating..." : "💾 Update Profile"}
        </button>

        {/* Divider */}
        <div className="border-t pt-8 space-y-4">
          <h3 className="text-lg font-semibold flex items-center gap-2">
            🔒 Change Password
          </h3>

          <div className="space-y-3">
            <input
              type="password"
              placeholder="Current Password"
              className="input w-full"
              value={currentPassword}
              onChange={(e) => setCurrentPassword(e.target.value)}
            />

            <input
              type="password"
              placeholder="New Password"
              className="input w-full"
              value={newPassword}
              onChange={(e) => setNewPassword(e.target.value)}
            />
          </div>

          <button
            className="btn btn-secondary w-full"
            onClick={handleChangePassword}
            disabled={loading}
          >
            {loading ? "Changing..." : "Change Password"}
          </button>
        </div>
      </div>
    </div>
  );
}
